var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"......놀라운걸.","JPN":"……これは驚きました。","ENG":"That’s impressive.","TWN":"……真是令人吃驚啊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"정말로 그 포위망을 돌파할 줄은 몰랐어.","JPN":"本当にあの包囲網を突破できると思わなかったわ。","ENG":"I didn’t know you’d actually break through the siege.","TWN":"沒想到你們真的能突破那個包圍網。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"이건 정말 궁금해서 묻는 건데, 당신들 진짜 정체가 뭐야?","JPN":"これは本当に知りたくて聞くんだけど、あなたたちはいったい何者なの？","ENG":"Seriously, I’m asking this out of curiosity... Who are you people?","TWN":"我真的很好奇，你們到底是什麼人啊？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"다 망해 가는 작은 태스크포스 컴퍼니의 용병이라기엔 실력이 너무 비상식적이잖아?","JPN":"廃業寸前の小さなタスクフォースカンパニーの傭兵にしては、あまりにも桁外れの実力じゃない。","ENG":"I mean you’re way too capable to be working as mercenaries for a tiny TASKFORCE company on the verge of bankruptcy.","TWN":"一家快倒閉的特遣勢力小公司的傭兵，這個實力也太不尋常了吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"칭찬 고맙군.","JPN":"褒め言葉をありがとう。","ENG":"I appreciate the compliment.","TWN":"多謝誇獎。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"정말로 그렇게 생각한다면 지금이라도 길을 비켜주는 건 어때?","JPN":"本当にそう思うなら、今からでも道を開けてくれないか？","ENG":"Now, if you really hold us in such high regard, why don’t you let us through?","TWN":"妳要是真的這麼想的話，現在就把路讓開怎麼樣？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"......미안해요, 펜릴 소대장님.","JPN":"……ごめんなさい。フェンリル小隊長。","ENG":"Sorry, Commander Hilde.","TWN":"……抱歉，芬里爾小隊隊長。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"저도 당신들과 직접 싸우는 건 내키지 않지만......","JPN":"私もあなた方と直接戦うのは気が進まないですが……","ENG":"I really wish I didn’t have to fight you guys myself...","TWN":"雖然我也不想和妳直接戰鬥……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"새 직장에 취업한 지 얼마 안 되서 말이죠.","JPN":"新しい職場に就いたばかりなので。","ENG":"But I just got this new job, you see.","TWN":"但我的新工作才就職沒多久。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"근면성실한 모습을 보여 줘야 할 시기 아니겠어요?","JPN":"真面目なところをアピールすべきだと思いません？","ENG":"I need to show them what a diligent employee I am, you know?","TWN":"這個時期不就是該表現出勤奮的樣子嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"그리고......","JPN":"それに……","ENG":"Besides...","TWN":"而且……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"모습들을 보아하니 무리해서 포위망을 돌파하느라 다들 꽤 지친 것 같은데......","JPN":"皆さんの様子を見る限り、包囲網の突破でかなりお疲れのようですが……","ENG":"You all seem quite exhausted from trying to break that siege...","TWN":"就我看來，你們硬是突破了包圍網，所有人都很累的樣子……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"그 정도면 제게도 기회가 있지 않을까요?","JPN":"これなら、私にも勝機はあるんじゃないですかね？","ENG":"So maybe I've got a shot after all?","TWN":"這樣的話我就有機會了吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......시끄러워.","JPN":"……うるさいな。","ENG":"Shut up.","TWN":"……吵死了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너 정도 때려눕힐 힘은 아직 충분해.","JPN":"あんたを殴り倒す力はまだ十分に残ってるから。","ENG":"We still got enough juice to knock you out.","TWN":"把妳打倒的力氣還有很多啦。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"어머, 기운차기도 해라.","JPN":"まあ、それは頼もしいこと。","ENG":"Oh my, aren’t you a sprightly little thing.","TWN":"哎呀，還真是鬥志高昂啊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"뭐, 좋아. 나도 너와는 한 번쯤 붙어보고 싶었거든.","JPN":"まあ、いいや。私もあなたとは一度ぐらい対決してみたかったからね。","ENG":"Fine. I always wanted to go toe-to-toe with you eventually.","TWN":"那好吧。我也正好想要和妳打一架呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......실비아.","JPN":"……シルビア。","ENG":"Sylvia...","TWN":"……希爾維亞。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"왜?","JPN":"何？","ENG":"Yeah?","TWN":"怎麼了？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"혹시나 해서 묻는 건데...... 비장의 수단 같은 건 없나?","JPN":"念のため聞いておきたいが……秘蔵の技とかはないか？","ENG":"I’m asking, just in case... Do you have any aces up your sleeve?","TWN":"以防萬一我問一下……妳沒有什麼殺手鐧嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그야...... 없는 건 아닌데......","JPN":"そりゃ……ないわけではないけど……","ENG":"Well... I do, sorta...","TWN":"那個……也不是沒有……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"준비에 시간이 좀 걸려.","JPN":"準備に少し時間がかかる。","ENG":"But it will take some time to prep.","TWN":"但得花時間準備。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"시간이라...... 꽤 곤란한 주문이로군.","JPN":"時間か……そいつはまいったな。","ENG":"Time, huh... The one thing we're very short on right now.","TWN":"時間啊……這還真有點為難。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......하지만 내가 어떻게든 해 보도록 하지.","JPN":"……でも、私が何とかする。","ENG":"Very well. I’ll see what I can do.","TWN":"……但是不管怎樣我都會試試看的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그러니 마무리를 지을 수 있도록 준비해 주면 좋겠군.","JPN":"だから、とどめを刺せるように準備してほしい。","ENG":"Meanwhile, begin preparing whatever it is you've got to end this once and for all.","TWN":"所以妳就準備好結束這一切吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......알았어. 그건 내게 맡겨.","JPN":"……わかった。それはアタシに任せて。","ENG":"Got it. Leave that to me.","TWN":"……知道了。交給我吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"PAWN_REPLACER_NULL_SPLIT","text":{"KOREA":"버러지들아!","JPN":"虫けらども！","ENG":"You little bugs!","TWN":"螻蟻們！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PAWN_REPLACER_NULL_SPLIT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PAWN_REPLACER_NULL_SPLIT","text":{"KOREA":"내가 돌아왔다!","JPN":"この俺が戻ってきた！","ENG":"I have returned!","TWN":"我回來了！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PAWN_REPLACER_NULL_SPLIT","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PAWN_REPLACER_NULL_SPLIT","text":{"KOREA":"쓸모없는 것들......","JPN":"この役立たずめ……","ENG":"You useless scum!","TWN":"沒用的東西……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PAWN_REPLACER_NULL_SPLIT","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PAWN_REPLACER_NULL_SPLIT","text":{"KOREA":"밟아 죽인다! 밟고 터뜨린다!","JPN":"踏み殺してやる！　踏んづけて、破裂させてやる！","ENG":"I stomp! I stomp and kill you!","TWN":"踩死你們！踩爛你們！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PAWN_REPLACER_NULL_SPLIT","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PAWN_REPLACER_NULL_SPLIT","text":{"KOREA":"나는 핀리...... 나는 리플레이서...... 나는 폰 분열체......","JPN":"俺はフィンリー……俺はリプレイサー……俺はポーン分裂体……","ENG":"I am Finley... I am Replacer... I am Pawn...","TWN":"我是芬利……我是克隆集團……我是兵卒分裂體……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"PAWN_REPLACER_NULL_SPLIT","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"PAWN_REPLACER_NULL_SPLIT","text":{"KOREA":"나는 누구지......?","JPN":"俺は、誰だ……？","ENG":"I am... Who??","TWN":"我是誰……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"PAWN_REPLACER_NULL_SPLIT","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"히익?! 저, 저게 뭐야?","JPN":"ひいっ！？　なに、あれ？","ENG":"Eeek! W-what the heck is that?","TWN":"咿？！那是什麼？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"저도 경찰 노릇 하면서 이거 저거 못 볼 꼴 많이 봤다고 생각했는데......","JPN":"私も警察の仕事で色々と散々なものを見てきたと思うけど……","ENG":"I thought I'd seen all there is to see in the line of duty...","TWN":"我還以為我當警察已經見識夠多了……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이건 좀 놀랍네요.","JPN":"これは驚きました。","ENG":"But this tops the chart.","TWN":"這還真是令人吃驚。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"과연 하늘 위엔 또 하늘이 있는 거군요.","JPN":"上には上がいるってわけですか。","ENG":"I guess there’s always something new to see in this world.","TWN":"果然是人外有人，天外有天啊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"또 저 녀석들이야......?","JPN":"またあいつらなの……？","ENG":"Them again?","TWN":"又是那些傢伙們嗎……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 반가운 얼굴이네요.","JPN":"ハハ、これは嬉しいメンツですね。","ENG":"Haha, it’s always nice to see a familiar face.","TWN":"哈哈，很高興又見面了呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"반가워? 선배는 도대체 취향이 어떻게 되어먹은 거야?","JPN":"嬉しい？　先輩の趣味、おかしくない？","ENG":"Nice? You know, you're a totally creep sometimes.","TWN":"高興？前輩你到底有什麼癖好啊？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"경찰 여러분들도 조심하세요.","JPN":"警察の皆さんも気をつけてくださいね。","ENG":"Watch out, officers.","TWN":"各位警察也要小心。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"생긴 건 웃기게 생겼어도 힘은 어지간한 중형 침식체 못지 않으니까요.","JPN":"あんな笑える見た目でも、中型侵食体に劣らない力持ちですから。","ENG":"He may look funny, but he packs the punch of a heavyweight C.O.","TWN":"雖然長得很滑稽，但力量幾乎不輸給中型侵蝕體。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"웃기게 생겼다고?","JPN":"笑える見た目ですって？","ENG":"Funny?","TWN":"長得很滑稽？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"대체 저거의 어딜 보고 웃어야 하는 건데......?","JPN":"いったいあれのどこが笑えるわけ？","ENG":"What part of that is supposed to make me laugh?","TWN":"到底是哪裡長得好笑了……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......스승님.","JPN":"……師匠。","ENG":"Master...","TWN":"……師父。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"왜 그러지?","JPN":"何だ？","ENG":"What is it?","TWN":"幹嘛？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"알고 계시겠지만, 미나 양이 무의식 중에 방출하는 힘이 점점 커지고 있어요.","JPN":"気づいていると思いますが、ミナさんの無意識に放出する力がますます大きくなっています。","ENG":"You may have caught on already, but Mina’s been subconsciously emitting an increasing amount of energy.","TWN":"妳也知道，米娜小姐無意識間放出的能量正逐漸變大。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이대로 계속 두고 보실 건가요?","JPN":"このままずっと見守るつもりですか。","ENG":"Are you just going to sit back and watch?","TWN":"妳就要這樣放任不管嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아니면......","JPN":"それとも……","ENG":"Or will you...","TWN":"還是說……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아직...... 아직은 아니야.","JPN":"まだ……まだ早い。","ENG":"No... Not yet.","TWN":"還沒……還沒有。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아직 선을 넘지는 않았어.","JPN":"まだ一線は越えていない。","ENG":"She hasn’t crossed the line yet.","TWN":"還沒有超過那條線。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"나유빈이 했던 것처럼...... 강제로 추출하지 않는 이상......","JPN":"イチノセのように……強制的に抽出しない限り……","ENG":"As long as we don’t do what Yubin did... and forcibly extract it from her...","TWN":"就像羅瑜斌曾經做的……如果沒有強制提取的話……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>놈들</color>이 깨어날 정도는 아니니까.","JPN":"<color=#ffd34c>奴ら</color>が目覚めるほどではない。","ENG":"It’s not enough to wake <color=#ffd34c>them</color> up.","TWN":"<color=#ffd34c>那些傢伙們</color>還不足以覺醒……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>놈들</color>이라......","JPN":"<color=#ffd34c>奴ら</color>ですか……","ENG":"<color=#ffd34c>Them</color>, you say?","TWN":"<color=#ffd34c>那些傢伙</color>……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};